const express = require('express');
const app = express();
const PORT = 3000;

const authorizationCodes = {};

app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri } = req.query;

  // Check client_id and redirect_uri
  if (!client_id || !redirect_uri) {
    return res.status(400).send('Missing parameters');
  }

  // Display authorization form
  res.send(`
    <h1>Authorize</h1>
    <form method="POST" action="/authorize">
      <input type="hidden" name="client_id" value="${client_id}">
      <input type="hidden" name="redirect_uri" value="${redirect_uri}">
      <button type="submit">Authorize</button>
    </form>
  `);
});

app.post('/authorize', (req, res) => {
  const { client_id, redirect_uri } = req.body;

  // Generate authorization code
  const authorizationCode = Math.random().toString(36).substring(7);
  authorizationCodes[authorizationCode] = { client_id, redirect_uri };

  // Redirect user
  res.redirect(`${redirect_uri}?code=${authorizationCode}`);
});

app.post('/token', (req, res) => {
  const { code, client_id } = req.body;

  // Validate authorization code
  if (!authorizationCodes[code] || authorizationCodes[code].client_id !== client_id) {
    return res.status(400).send('Invalid authorization code');
  }

  // Issue access token
  const accessToken = Math.random().toString(36).substring(7);

  // Clear authorization code
  delete authorizationCodes[code];

  // Return access token
  res.json({ access_token: accessToken, token_type: 'Bearer' });
});

